$1<script>
(function(){
try{
  var scriptEl=document.currentScript;
  if(!scriptEl) return;
  var T; try{T=window.top||window}catch(_){T=window}
  var D=T.document||document;

  function ensureSTGAPI(){
    if(T.STG_API) return T.STG_API;
    var INDEX_FILE='storage_index.json';
    function uid(){return 'id'+Date.now().toString(36)+Math.random().toString(36).slice(2,7);}
    async function loadIndex(){
      try{ var txt=await tavo.file.load(INDEX_FILE,{scope:'global'}); if(txt){var d=JSON.parse(txt); if(d&&d.folders) return d;} }catch(e){}
      return {folders:[]};
    }
    async function saveIndex(idx){ await tavo.file.save(INDEX_FILE, JSON.stringify(idx), {scope:'global', encoding:'utf8'}); }
    function extractImgSrc(html){ if(!html) return null; var m=/<img[^>]+src=["']([^"']+)["']/i.exec(html); return m?m[1]:null; }
    function extractMusicLink(text){
      if(!text) return null;
      var m=/https?:\/\/\S*(music\.163\.com|y\.qq\.com|spotify\.com|music\.apple\.com|kuwo\.cn|kugou\.com)\S*/i.exec(text);
      if(m) return m[0];
      var m2=/https?:\/\/\S+\.(mp3|m4a|wav|flac)(\?\S*)?/i.exec(text);
      return m2?m2[0]:null;
    }
    async function persistImage(src){
      var name='img_'+uid()+'.png';
      try{
        if(/^data:/.test(src)) return await tavo.file.save(name,src,{scope:'global'});
        if(/^https?:\/\//.test(src)) return await tavo.file.save(name,src,{scope:'global'});
        var dataUrl=await tavo.file.load(src.replace(/^files\/(chat|global)\//,''),{encoding:'dataUrl'});
        if(dataUrl) return await tavo.file.save(name,dataUrl,{scope:'global'});
      }catch(e){}
      return src;
    }
    async function getDefaultFolderId(idx){
      var last=null; try{ last=tavo.get('stg_last_folder'); }catch(e){}
      if(last && idx.folders.some(function(f){return f.id===last;})) return last;
      var def=idx.folders.find(function(f){return f.name==='未分类收藏';});
      if(def) return def.id;
      var nf={id:uid(),name:'未分类收藏',items:[]};
      idx.folders.push(nf);
      return nf.id;
    }
    async function isCollected(msgId){
      var idx=await loadIndex();
      for(var i=0;i<idx.folders.length;i++){
        var f=idx.folders[i];
        if(f.items && f.items.some(function(it){return it.sourceMessageId===msgId;})) return true;
      }
      return false;
    }
    async function toggleCollect(msg){
      var idx=await loadIndex();
      var found=null, foundFolder=null;
      for(var i=0;i<idx.folders.length;i++){
        var f=idx.folders[i];
        var it=(f.items||[]).find(function(x){return x.sourceMessageId===msg.id;});
        if(it){ found=it; foundFolder=f; break; }
      }
      if(found){
        foundFolder.items=foundFolder.items.filter(function(x){return x.id!==found.id;});
        await saveIndex(idx);
        return {collected:false, folderName:foundFolder.name};
      }
      var text=msg.content||'';
      var img=extractImgSrc(text);
      var music=extractMusicLink(text);
      var type='text', content=text;
      if(img){ type='image'; content=await persistImage(img); }
      else if(music){ type='audio'; content=music; }
      var folderId=await getDefaultFolderId(idx);
      var folder=idx.folders.find(function(f){return f.id===folderId;});
      var chatName='未知聊天'; try{ var chat=await tavo.chat.current(); if(chat&&chat.name) chatName=chat.name; }catch(e){}
      folder.items=folder.items||[];
      folder.items.push({id:uid(), type:type, content:content, chatName:chatName, ts:Date.now(), sourceMessageId:msg.id});
      await saveIndex(idx);
      try{ tavo.set('stg_last_folder', folder.id); }catch(e){}
      return {collected:true, folderName:folder.name, type:type};
    }
    T.STG_API={loadIndex:loadIndex,saveIndex:saveIndex,uid:uid,extractImgSrc:extractImgSrc,extractMusicLink:extractMusicLink,persistImage:persistImage,isCollected:isCollected,toggleCollect:toggleCollect};
    return T.STG_API;
  }

  var API=ensureSTGAPI();

  function itoast(msg){
    var el=D.getElementById('stg-toast')||(function(){var e=D.createElement('div');e.id='stg-toast';e.style.cssText='position:fixed;top:20px;left:50%;transform:translateX(-50%);background:rgba(16,20,38,0.95);color:#e2e8f0;padding:9px 18px;border-radius:20px;font-size:13px;z-index:10000;border:1px solid rgba(59,130,246,0.3);opacity:0;transition:opacity .25s;pointer-events:none;white-space:nowrap;';D.body.appendChild(e);return e;})();
    el.textContent=msg; el.style.opacity='1'; el.style.top='60px';
    clearTimeout(el._t);
    el._t=setTimeout(function(){ el.style.opacity='0'; el.style.top='20px'; },2200);
  }

  (async function(){
    try{
      var msg=await tavo.message.current();
      if(!msg) return;
      var collected=await API.isCollected(msg.id);
      var icon=D.createElement('span');
      icon.textContent=collected?'⭐':'☆';
      icon.title='点击收藏/取消收藏';
      icon.style.cssText='display:inline-block;cursor:pointer;font-size:16px;margin-left:6px;vertical-align:middle;opacity:0.85;user-select:none;';
      icon.addEventListener('click', async function(e){
        e.stopPropagation();
        var prev=icon.textContent;
        icon.textContent='⏳';
        try{
          var res=await API.toggleCollect(msg);
          icon.textContent = res.collected ? '⭐' : '☆';
          itoast(res.collected ? ('✅ 已收藏到「'+res.folderName+'」') : '已取消收藏');
        }catch(err){
          console.error('[收藏图标]',err);
          icon.textContent=prev;
          itoast('❌ 操作失败');
        }
      });
      scriptEl.parentNode.insertBefore(icon, scriptEl);
    }catch(err){ console.error('[收藏图标]',err); }
  })();
}catch(e){console.error('[收藏图标]',e);}
})();
</script>

